provider "aws" {
  region = "us-east-2"
}

resource "aws_s3_bucket" "secure_bucket" {
  bucket = "iac-scanner-demo-bucket-paulh-secure"
}

resource "aws_s3_bucket_acl" "secure_bucket_acl" {
